360	
361		// Compare: is the binary older than what the project requires?
362		needsUpgrade, err := update.NeedsUpgrade(f.Version, projectVersion)
363		if err != nil {
364			return nil // Parse error — don't block
365		}
366		if needsUpgrade {
367			return fmt.Errorf("this project requires DDx v%s or newer (you have %s).\nRun 'ddx upgrade' to update your DDx binary",
368				strings.TrimPrefix(projectVersion, "v"),
369				f.Version)
370		}
371	
372		return nil
373	}
