375	// displayStalenessHints shows soft hints when project skills or plugins are outdated.
376	func (f *CommandFactory) displayStalenessHints(cmd *cobra.Command) {
377		// Skip for machine-readable output
378		if jsonFlag, _ := cmd.Flags().GetBool("json"); jsonFlag {
379			return
380		}
381		if silentFlag, _ := cmd.Flags().GetBool("silent"); silentFlag {
382			return
383		}
384		// Skip when stdout is not a terminal (pipes, scripts, CI)
385		if !isatty.IsTerminal(os.Stdout.Fd()) && !isatty.IsCygwinTerminal(os.Stdout.Fd()) {
386			return
387		}
388	
389		// Dev builds don't hint
390		if f.Version == "" || f.Version == "dev" {
391			return
392		}
393	
394		// Check project staleness
395		projectVersion := readProjectVersions(f.WorkingDir)
396		if projectVersion != "" && projectVersion != "dev" {
397			// Is the binary newer than the project?
398			projectNeedsUpgrade, err := update.NeedsUpgrade(projectVersion, f.Version)
399			if err == nil && projectNeedsUpgrade {
400				_, _ = fmt.Fprintf(cmd.OutOrStdout(),
401					"\n💡 Project skills from DDx v%s (you have %s). Run 'ddx init --force' to update.\n",
402					strings.TrimPrefix(projectVersion, "v"),
403					f.Version)
404			}
405		}
406	
407		// Check plugin staleness (reuse ddx outdated logic)
408		f.displayPluginStalenessHints(cmd)
409	}
