411	// displayPluginStalenessHints reads the plugin version cache and shows hints for
412	// any installed plugins that have a newer version available.
413	func (f *CommandFactory) displayPluginStalenessHints(cmd *cobra.Command) {
414		state, err := registry.LoadState()
415		if err != nil || len(state.Installed) == 0 {
416			return
417		}
418	
419		cache := update.NewPluginCache()
420		if err := cache.Load(); err != nil {
421			return // no cache yet — check runs in background, hints appear next time
422		}
423	
424		for _, entry := range state.Installed {
425			latestVersion, ok := cache.Data.Plugins[entry.Name]
426			if !ok {
427				continue
428			}
429			needsUpgrade, err := update.NeedsUpgrade(entry.Version, latestVersion)
430			if err == nil && needsUpgrade {
431				_, _ = fmt.Fprintf(cmd.OutOrStdout(),
432					"\n💡 %s %s installed, %s available. Run 'ddx install %s' to update.\n",
433					entry.Name, entry.Version, latestVersion, entry.Name)
434			}
435		}
436	}
