438	// refreshPluginVersionCache fetches the latest version for each installed plugin
439	// from GitHub and writes the result to the plugin cache. Called from the
440	// background update goroutine — failures are silent.
441	func (f *CommandFactory) refreshPluginVersionCache() {
442		cache := update.NewPluginCache()
443		_ = cache.Load() // ignore missing-file error
444	
445		if !cache.IsExpired() {
446			return
447		}
448	
449		state, err := registry.LoadState()
450		if err != nil || len(state.Installed) == 0 {
451			return
452		}
453	
454		reg := registry.BuiltinRegistry()
455		updated := false
456		for _, entry := range state.Installed {
457			pkg, err := reg.Find(entry.Name)
458			if err != nil {
459				continue
460			}
461			release, err := update.FetchLatestReleaseForRepo(pkg.Source)
462			if err != nil {
463				continue
464			}
465			latestVersion := strings.TrimPrefix(release.TagName, "v")
466			cache.Data.Plugins[entry.Name] = latestVersion
467			updated = true
468		}
469	
470		if updated {
471			cache.Data.LastCheck = time.Now()
472			_ = cache.Save()
473		}
474	}
